-- Merade Immobilier — restore ten published properties.
-- Safe to run repeatedly: an existing property with the same title is preserved.

insert into public.properties (
  title, category, status, wilaya, commune, address, price, currency,
  surface, rooms, bedrooms, bathrooms, floor, description, features, images,
  featured, hero_featured, hero_order, is_published, created_at
)
select
  v.title, v.category, v.status, v.wilaya, v.commune, v.address, v.price, v.currency,
  v.surface, v.rooms, v.bedrooms, v.bathrooms, v.floor, v.description, v.features, v.images,
  v.featured, v.hero_featured, v.hero_order, true, v.created_at
